mapper.select:
select cDefaultValue from billitem_base

    ibillid = (select id from bill_base where cbillno = 'cmp_receivebill' and tenant_id = #{tenantid})
    and  cFieldName='quickType.code' and cDataSourceName='cmp.receivebill.ReceiveBill_b'

        and iTplId = #{tplid}

limit 1;

select cDefaultValue from billitem_base

    ibillid = (select id from bill_base where cbillno = 'cmp_payment' and tenant_id = #{tenantid})
    and cFieldName='quickType.code' and cDataSourceName='cmp.paybill.PayBillb'

        and iTplId = #{tplid}

limit 1;

select cDefaultValue from billitem_base

    ibillid = (select id from bill_base where cbillno = 'cmp_payapplicationbill' and tenant_id = #{tenantid})
    and cFieldName='quickType.code' and cDataSourceName='cmp.payapplicationbill.PayApplicationBill_b'

        and iTplId = #{tplid}

limit 1;

select cDefaultValue from billitem_base

    ibillid = (select id from bill_base where cbillno = 'cmp_fundPayment' and tenant_id = #{tenantid})
    and cFieldName='quickType.code' and cDataSourceName='cmp.fundpayment.FundPayment_b' limit 1;

select cDefaultValue from billitem_base

    ibillid = (select id from bill_base where cbillno = 'cmp_fundcollection' and tenant_id = #{tenantid})
    and cFieldName='quickType.code' and cDataSourceName='cmp.fundcollection.FundCollection_b' limit 1;
